Usage: `python3 bigfiles.py /path/to/scan --threshold 50`. Catches `OSError` for unreadable files (broken symlinks, permission errors) and skips them silently. Sorts in-memory which is fine until you have millions of matches.

```python
#!/usr/bin/env python3
"""Find files larger than a threshold."""
import argparse
import sys
from pathlib import Path

def main():
    p = argparse.ArgumentParser(description="List files above a size threshold.")
    p.add_argument("path", type=Path, help="Root directory to scan")
    p.add_argument("--threshold", type=float, default=100.0, help="Threshold in MB (default 100)")
    p.add_argument("--top", type=int, default=0, help="Limit output to the N largest files (default unlimited)")
    p.add_argument("--verbose", action="store_true", help="Print skip reasons to stderr")
    args = p.parse_args()

    threshold_bytes = int(args.threshold * 1024 * 1024)
    rows = []
    for f in args.path.rglob("*"):
        if not f.is_file():
            continue
        try:
            size = f.stat().st_size
        except (OSError, PermissionError) as e:
            if args.verbose:
                print(f"skip {f}: {type(e).__name__}: {e}", file=sys.stderr)
            continue
        if size >= threshold_bytes:
            rows.append((size, f))

    rows.sort(reverse=True)
    if args.top > 0:
        rows = rows[: args.top]
    for size, path in rows:
        size_mb = size / (1024 * 1024)
        print(f"{size_mb:7.1f}MB  {path}")

if __name__ == "__main__":
    main()
```

The `--top N` slice happens after sorting. Setting `--top 0` (default) means unlimited. Verbose output goes to stderr so it doesn't pollute the size listing on stdout.

Right — PermissionError IS an OSError, the duplicate is dead code. For symlink loops, the cleanest approach is to walk with `os.walk(followlinks=False)` and track inodes we've seen; rglob doesn't expose follow-link control. Here:

```python
#!/usr/bin/env python3
"""Find files larger than a threshold."""
import argparse
import os
import sys
from pathlib import Path

def walk_files(root, *, follow_symlinks=False, verbose=False):
    """Yield (size, Path) for regular files under root."""
    seen = set()  # (st_dev, st_ino) for cycle detection when following links
    for dirpath, dirnames, filenames in os.walk(root, followlinks=follow_symlinks):
        if follow_symlinks:
            try:
                st = os.stat(dirpath)
            except OSError as e:
                if verbose:
                    print(f"skip dir {dirpath}: {e}", file=sys.stderr)
                dirnames[:] = []
                continue
            key = (st.st_dev, st.st_ino)
            if key in seen:
                if verbose:
                    print(f"skip dir {dirpath}: symlink cycle", file=sys.stderr)
                dirnames[:] = []
                continue
            seen.add(key)
        for name in filenames:
            f = Path(dirpath) / name
            try:
                size = f.stat().st_size
            except OSError as e:
                if verbose:
                    print(f"skip {f}: {e}", file=sys.stderr)
                continue
            yield size, f

def main():
    p = argparse.ArgumentParser(description="List files above a size threshold.")
    p.add_argument("path", type=Path, help="Root directory to scan")
    p.add_argument("--threshold", type=float, default=100.0)
    p.add_argument("--top", type=int, default=0)
    p.add_argument("--follow-symlinks", action="store_true")
    p.add_argument("--verbose", action="store_true")
    args = p.parse_args()

    threshold_bytes = int(args.threshold * 1024 * 1024)
    rows = [
        (size, f)
        for size, f in walk_files(
            args.path,
            follow_symlinks=args.follow_symlinks,
            verbose=args.verbose,
        )
        if size >= threshold_bytes
    ]

    rows.sort(reverse=True)
    if args.top > 0:
        rows = rows[: args.top]
    for size, path in rows:
        size_mb = size / (1024 * 1024)
        print(f"{size_mb:7.1f}MB  {path}")

if __name__ == "__main__":
    main()
```

Default behavior is `followlinks=False` which short-circuits the cycle problem entirely. The cycle detection only runs when `--follow-symlinks` is passed; we record `(st_dev, st_ino)` for each visited directory (works across mountpoints). Pruning `dirnames[:] = []` tells `os.walk` not to descend further into a node we've already visited.
